fr:mainmatter.fr:pre:
\title{Jon Sterling}
\taxon{person}
\meta{external}{https://www.jonmsterling.com/}
\meta{institution}{[[ucam]]}
\meta{orcid}{0000-0002-0585-5564}
\meta{position}{Associate Professor}

\p{Associate Professor in Logical Foundations and Formal Methods at University of Cambridge. Formerly a [Marie Skłodowska-Curie Postdoctoral Fellow](jms-0061) hosted at Aarhus University by [Lars Birkedal](larsbirkedal), and before this a PhD student of [Robert Harper](robertharper).}

\title{creation of (co)limits}
\date{2023-02-11}
\taxon{definition}
\author{jonmsterling}

\def\CCat{#{\mathcal{C}}}
\def\DCat{#{\mathcal{D}}}
\def\ICat{#{\mathcal{I}}}
\def\Mor[arg1][arg2][arg3]{#{{\arg2}\xrightarrow{\arg1}{\arg3}}}

\p{Let \Mor{U}{\CCat}{\DCat} be a functor and let \ICat be a category. The functor #{U} is said to \em{create (co)limits of #{\ICat}-figures} when for any diagram \Mor{C_\bullet}{\ICat}{\CCat} such that #{\ICat\xrightarrow{C_\bullet}\CCat\xrightarrow{F}\DCat} has a (co)limit, then #{C_\bullet} has a (co)limit that is both preserved and reflected by #{F}.}

% Allocate a fluid binding to hold the default LaTeX preamble,
% e.g. for loading tikz packages.
\alloc\base/tex-preamble

\def\texfig[body]{
 \scope{
  % Install a LaTeX preamble to be used by default if none is set.
  \put?\base/tex-preamble{
   % Some useful things from my own library.
   \latex-preamble/string-diagrams
   \latex-preamble/diagrams
  }

  % Wrap the diagram in a figure
  \figure{
   % Render the LaTeX code with the current preamble
   \tex{\get\base/tex-preamble}{\body}
  }
 }
}

\def\my-object{
  \object[self]{
    [method1]{
      the implementation of this method
    }
    [method2]{
      the implementation of another method
      \self#method1
    }
  }
}

{
 inputs = {
   forester = {
     url = "sourcehut:~jonsterling/ocaml-forester";
   };
   flake-utils.url = "github:numtide/flake-utils";
 };
 outputs =
   { self
   , flake-utils
   , nixpkgs
   , forester
   }:
   flake-utils.lib.eachDefaultSystem
     (system:
     let
       pkgs = import nixpkgs { inherit system; };
       legacyPackages = import forester.legacyPackages.${system};
     in
     {
       devShell =
         pkgs.mkShell {
           buildInputs = with pkgs; [
             forester.packages.${system}.default
             texlive.combined.scheme-full
             fswatch
           ];
         };
     });
}

